        n = len(s)
        if k == 0:
            return 0

        # Precompute cost[a][b] for all substrings s[a..b]
        cost = [[0] * n for _ in range(n)]
        for a in range(n):
            for b in range(a, n):
                l = b - a + 1
                if l == 1:
                    cost[a][b] = float('inf')
                    continue
                min_cost = float('inf')
                divisors = self.get_divisors(l)
                if not divisors:
                    cost[a][b] = float('inf')
                    continue
                for d in divisors:
                    total = 0
                    for i in range(d):
                        group = []
                        for j in range(i, l, d):
                            group.append(s[a + j])
                        # Calculate changes needed for this group to be a palindrome
                        changes = 0
                        left = 0
                        right = len(group) - 1
                        while left < right:
                            if group[left] != group[right]:
                                changes += 1
                            left += 1
                            right -= 1
                        total += changes
                    if total < min_cost:
                        min_cost = total
                cost[a][b] = min_cost

        # Initialize DP table
        INF = float('inf')
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for j in range(1, k + 1):
                if j > i:
                    continue
                for m in range(j - 1, i):
                    current_cost = cost[m][i - 1]
                    if current_cost == INF:
                        continue
                    if dp[m][j - 1] + current_cost < dp[i][j]:
                        dp[i][j] = dp[m][j - 1] + current_cost

        return dp[n][k] if dp[n][k] != INF else -1

